// Validate input payload + secret
const payload = $input.first().json;
const secret = process.env.N8N_WEBHOOK_SECRET || '';

if (secret && payload.secret !== secret) {
  throw new Error('Invalid webhook secret');
}

const required = ['repo_url', 'branch', 'task_id', 'project_id'];
for (const field of required) {
  if (!payload[field]) throw new Error(`Missing required field: ${field}`);
}

return [{ json: {
  repo_url: payload.repo_url,
  branch: payload.branch,
  task_id: payload.task_id,
  project_id: payload.project_id
}}];

// Build SSH review command — Base64-encode to avoid shell injection
const ctx = $input.first().json;

const reviewData = JSON.stringify({
  repo_url: ctx.repo_url,
  branch: ctx.branch,
  task_id: ctx.task_id,
  project_id: ctx.project_id
});

const b64 = Buffer.from(reviewData).toString('base64');
return [{ json: { ...ctx, review_data_b64: b64 } }];

const { exec } = require('child_process');
const keyPath = process.env.WORKSTATION_SSH_KEY_PATH || '/home/mobuone/.ssh/seko-vpn-deploy';
const piUser = process.env.WORKSTATION_PI_USER || 'mobuone';
const piIp = process.env.WORKSTATION_PI_IP;
const b64 = $input.first().json.review_data_b64;
const cmd = `ssh -i ${keyPath} -o StrictHostKeyChecking=accept-new -o ConnectTimeout=15 ${piUser}@${piIp} 'echo ${b64} | base64 -d | claude-code-review --stdin --model gpt-codex'`;
const result = await new Promise((resolve) => {
  exec(cmd, { timeout: 300000, maxBuffer: 10*1024*1024 }, (error, stdout, stderr) => {
    resolve({ stdout: stdout || '', stderr: stderr || '', exitCode: error ? (error.code || 1) : 0 });
  });
});
return [{ json: result }];

// Parse review result from SSH output
const raw = $input.first().json.stdout || '';
const exitCode = $input.first().json.exitCode ?? 0;

// Detect PASS/FAIL in output
const pass = raw.toUpperCase().includes('PASS') || raw.includes('✅');
const fail = raw.toUpperCase().includes('FAIL') || raw.includes('❌');

const status = pass ? 'PASS' : (fail ? 'FAIL' : 'UNKNOWN');
const success = exitCode === 0 && status === 'PASS';

// Truncate output for Palais comment (max 2000 chars)
const report = raw.slice(0, 2000);

const ctx = $('Validate payload').first().json;

return [{ json: {
  ...ctx,
  review_status: status,
  review_success: success,
  review_report: report,
  exit_code: exitCode
}}];

// SSH to Pi and merge the PR using gh CLI
const { exec } = require('child_process');
const ctx = $('Parse review result').first().json;
const keyPath = process.env.WORKSTATION_SSH_KEY_PATH || '/home/mobuone/.ssh/seko-vpn-deploy';
const piUser = process.env.WORKSTATION_PI_USER || 'mobuone';
const piIp = process.env.WORKSTATION_PI_IP;
const branch = ctx.branch || '';

// Extract owner/repo from repo_url (handles https and ssh git formats)
const repoUrl = ctx.repo_url || '';
const parts = repoUrl.replace(/\.git$/, '').split(/[:/]/);
const repoSlug = parts.slice(-2).join('/');

const cmd = `ssh -i ${keyPath} -o StrictHostKeyChecking=accept-new -o ConnectTimeout=15 ${piUser}@${piIp} 'gh pr merge --head ${branch} --repo ${repoSlug} --merge --delete-branch --yes 2>&1'`;

const result = await new Promise((resolve) => {
  exec(cmd, { timeout: 60000 }, (error, stdout, stderr) => {
    resolve({ stdout: stdout || '', stderr: stderr || '', exitCode: error ? (error.code || 1) : 0 });
  });
});

return [{ json: { ...ctx, merge_stdout: result.stdout, merge_exit_code: result.exitCode } }];

// Attach review report as text deliverable to the task
const ctx = $input.first().json;
const report = ($('Parse review result').first().json.review_report || '').trim() || '(rapport vide)';
const branch = ctx.branch || 'unknown';
const safeBranch = branch.replace(/[^a-zA-Z0-9-]/g, '-');
const filename = `review-${safeBranch}-${Date.now()}.txt`;
const palaisUrl = process.env.PALAIS_URL || 'http://palais:3300';
const apiKey = process.env.PALAIS_API_KEY || '';

let reportAttached = false;
let reportStatus = 0;

try {
  const formData = new FormData();
  const blob = new Blob([report], { type: 'text/plain' });
  formData.append('file', blob, filename);

  const res = await fetch(`${palaisUrl}/api/v1/tasks/${ctx.task_id}/deliverables`, {
    method: 'POST',
    headers: { 'X-API-Key': apiKey },
    body: formData
  });
  reportAttached = res.ok;
  reportStatus = res.status;
} catch (e) {
  // Non-blocking — continue even if upload fails
}

return [{ json: { ...ctx, report_attached: reportAttached, report_status: reportStatus } }];

// Classify incoming webhook: GitHub PR event vs Palais code-review request.
// Non-invasive: 'Validate payload' (existing node, Palais branch) still reads
// $input.first().json exactly as before — this node only adds a marker field,
// it never changes the shape Palais already relies on.
const raw = $input.first().json;
const body = (raw && typeof raw.body === 'object' && raw.body !== null) ? raw.body : raw;
const headers = raw.headers || {};
const ghEvent = (headers['x-github-event'] || headers['X-GitHub-Event'] || '').toString();
const isGithubPr = !!ghEvent && typeof body === 'object' && body !== null && !!body.pull_request && !!body.repository;
return [{ json: { ...raw, is_github_pr: isGithubPr } }];

// GitHub PR webhook payload parsing + action filter (T4.2).
// Secret deja verifie en amont par 'Valid webhook secret?' (node IF,
// expression n8n {{ $json.query.secret }} == {{ $env.GITHUB_WEBHOOK_SECRET }}
// — evaluee par le moteur d'expression n8n en processus principal, PAS dans
// ce Code node). Raison de cette separation, decouverte E2E (2026-07-18,
// execution 33896 — probe curl reelle) : le sandbox Code node de cette
// instance (Task Runner @n8n/task-runner) leve
// 'ReferenceError: process is not defined', alors meme que le template repo
// (roles/n8n/templates/n8n.env.j2) porte N8N_RUNNERS_ENABLED=false — derive
// constatee empiriquement entre config repo et conteneur deploye. process.env
// (et $env dans du JS Code node, meme bug documente GOTCHAS-N8N-2.30.md §7)
// sont donc inutilisables ici ; toute valeur d'env necessaire doit venir d'un
// node PARAMETRE (IF/Set) en amont. Ce node-ci ne fait que du parsing pur,
// aucun acces env requis.
const raw = $input.first().json;
const body = (raw && typeof raw.body === 'object' && raw.body !== null) ? raw.body : raw;

const action = body.action || '';
const pr = body.pull_request || {};
const repo = body.repository || {};
const repoFull = repo.full_name || '';
const prNumber = pr.number;

if (!['opened', 'synchronize'].includes(action)) {
  return [{ json: { skip: true, reason: `action '${action}' not opened/synchronize` } }];
}
if (!/^[A-Za-z0-9._-]+\/[A-Za-z0-9._-]+$/.test(repoFull)) {
  throw new Error(`repository.full_name invalide: '${repoFull}'`);
}
if (!Number.isInteger(prNumber) || prNumber <= 0) {
  throw new Error(`pull_request.number invalide: '${prNumber}'`);
}

return [{ json: {
  skip: false,
  reason: '',
  repo_full: repoFull,
  pr_number: prNumber,
  pr_branch: pr.head && pr.head.ref ? pr.head.ref : '',
  pr_title: pr.title || '',
  action
}}];

// Fire-and-forget: SSH vers waza, demarre review-pr-and-comment.sh detache
// (nohup + disown) et retourne immediatement — review-pr.sh peut prendre
// 3+ minutes (codex + escalade claude optionnelle), bien au-dela d'un
// timeout d'exec Code node raisonnable. Le wrapper poste le REVIEW.md
// resultant en commentaire PR via `gh pr comment`, entierement cote waza —
// n8n n'attend pas et ne recoit pas ce resultat.
// repo_full/pr_number ont deja ete strictement valides (regex + entier) en
// amont dans 'Validate GitHub PR webhook' — interpolation directe sure,
// meme modele de confiance que le node 'Merge PR' existant de ce workflow.
// keyPath/piUser/piIp viennent du node 'Prepare SSH env' (Set en amont,
// valeurs capturees via expression {{ $env.X }} evaluee par n8n hors du
// sandbox Code node — voir note dans 'Validate GitHub PR webhook' sur
// pourquoi process.env est inutilisable ici).
const { exec } = require('child_process');
const ctx = $input.first().json;
const keyPath = ctx.ssh_key_path || '/home/mobuone/.ssh/seko-vpn-deploy';
const piUser = ctx.pi_user || 'mobuone';
const piIp = ctx.pi_ip;
if (!piIp) throw new Error('WORKSTATION_PI_IP not configured (env var vide via Prepare SSH env)');

const repo = ctx.repo_full;
const pr = ctx.pr_number;
const remoteCmd = `mkdir -p /home/${piUser}/work/ops/loops/reviews && nohup /home/${piUser}/work/ops/loops/scripts/review-pr-and-comment.sh ${repo} ${pr} > /home/${piUser}/work/ops/loops/reviews/n8n-trigger-$(date +%s).log 2>&1 < /dev/null & disown; echo triggered`;
const cmd = `ssh -i ${keyPath} -o StrictHostKeyChecking=accept-new -o ConnectTimeout=15 ${piUser}@${piIp} '${remoteCmd}'`;

const result = await new Promise((resolve) => {
  exec(cmd, { timeout: 25000, maxBuffer: 1024 * 1024 }, (error, stdout, stderr) => {
    resolve({ stdout: stdout || '', stderr: stderr || '', exitCode: error ? (error.code || 1) : 0 });
  });
});
return [{ json: { ...ctx, ssh_trigger_stdout: result.stdout, ssh_trigger_stderr: result.stderr, ssh_trigger_exit_code: result.exitCode } }];
